/// Modelo de código de error ATM
class CodigoError {
  final int? id;
  final String codigoEstado;
  final String tipoError;
  final String descripcion;
  final String accionRecomendada;
  final String codigoHardware;

  CodigoError({
    this.id,
    required this.codigoEstado,
    required this.tipoError,
    required this.descripcion,
    required this.accionRecomendada,
    required this.codigoHardware,
  });

  Map<String, dynamic> toMap() {
    return {
      'id': id,
      'codigo_estado': codigoEstado,
      'tipo_error': tipoError,
      'descripcion': descripcion,
      'accion_recomendada': accionRecomendada,
      'codigo_hardware': codigoHardware,
    };
  }

  factory CodigoError.fromMap(Map<String, dynamic> map) {
    return CodigoError(
      id: map['id'],
      codigoEstado: map['codigo_estado'] ?? '',
      tipoError: map['tipo_error'] ?? '',
      descripcion: map['descripcion'] ?? '',
      accionRecomendada: map['accion_recomendada'] ?? '',
      codigoHardware: map['codigo_hardware'] ?? '',
    );
  }
}

/// Helper para base de datos de códigos de error ATM DT Series
class ErrorATMDatabase {
  static final ErrorATMDatabase instance = ErrorATMDatabase._init();
  static Database? _database;

  ErrorATMDatabase._init();

  Future<Database> get database async {
    if (_database != null) return _database!;
    _database = await _initDB('codigos_error_atm.db');
    return _database!;
  }

  Future<Database> _initDB(String filePath) async {
    final dbPath = await getDatabasesPath();
    final path = join(dbPath, filePath);

    return await openDatabase(
      path,
      version: 1,
      onCreate: _createDB,
    );
  }

  Future _createDB(Database db, int version) async {
    await db.execute('''
      CREATE TABLE codigos_error (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        codigo_estado TEXT NOT NULL,
        tipo_error TEXT,
        descripcion TEXT,
        accion_recomendada TEXT,
        codigo_hardware TEXT
      )
    ''');

    await _insertarDatosIniciales(db);
  }

  Future<void> _insertarDatosIniciales(Database db) async {
    final batch = db.batch();
    for (final row in _datosIniciales) {
      batch.insert('codigos_error', row);
    }
    await batch.commit(noResult: true);
  }

  /// Buscar por código de estado
  Future<List<CodigoError>> buscarPorCodigo(String codigo) async {
    final db = await instance.database;
    final result = await db.query(
      'codigos_error',
      where: 'codigo_estado = ?',
      whereArgs: [codigo],
    );
    return result.map((e) => CodigoError.fromMap(e)).toList();
  }

  /// Buscar por texto en descripción o acción
  Future<List<CodigoError>> buscarPorTexto(String texto) async {
    final db = await instance.database;
    final result = await db.query(
      'codigos_error',
      where: 'descripcion LIKE ? OR accion_recomendada LIKE ? OR tipo_error LIKE ?',
      whereArgs: ['%$texto%', '%$texto%', '%$texto%'],
    );
    return result.map((e) => CodigoError.fromMap(e)).toList();
  }

  /// Buscar por tipo de error
  Future<List<CodigoError>> buscarPorTipo(String tipo) async {
    final db = await instance.database;
    final result = await db.query(
      'codigos_error',
      where: 'tipo_error LIKE ?',
      whereArgs: ['%$tipo%'],
    );
    return result.map((e) => CodigoError.fromMap(e)).toList();
  }

  /// Obtener todos los registros
  Future<List<CodigoError>> obtenerTodos() async {
    final db = await instance.database;
    final result = await db.query('codigos_error', orderBy: 'CAST(codigo_estado AS INTEGER)');
    return result.map((e) => CodigoError.fromMap(e)).toList();
  }

  Future close() async {
    final db = await instance.database;
    db.close();
  }

